import ContextNode from "three/src/nodes/core/ContextNode.js";
import LightingModel, { LightingModelReflectedLight } from "three/src/nodes/core/LightingModel.js";
import Node from "../core/Node.js";
import LightsNode from "three/src/nodes/lighting/LightsNode.js";

export interface LightingContext {
    radiance: Node;
    irradiance: Node;
    iblIrradiance: Node;
    ambientOcclusion: Node;
    reflectedLight: LightingModelReflectedLight;
    backdrop: Node;
    backdropAlpha: Node;
}

export default class LightingContextNode extends ContextNode<unknown> {
    lightingModelNode: LightingModel | null;
    backdropNode: Node | null;
    backdropAlphaNode: Node | null;

    constructor(
        lightsNode: LightsNode,
        lightingModel?: LightingModel | null,
        backdropNode?: Node | null,
        backdropAlphaNode?: Node | null,
    );

    getContext(): LightingContext;
}

export const lightingContext: (
    node: LightsNode,
    lightingModelNode?: LightingModel,
) => LightingContextNode;
